'use client'

import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table'
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Skeleton } from '@/components/ui/skeleton'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import {
  Pagination,
  PaginationContent,
  PaginationItem,
  PaginationNext,
  PaginationPrevious,
} from '@/components/ui/pagination'
import { cn } from '@/lib/utils'

import { MoreHorizontal, Pencil, Trash } from 'lucide-react'

import { useDepartmentsList } from '../hooks/useDepartmentsList'
import { useDepartmentActions } from '../hooks/useDepartmentActions'
import { Department } from '../types/departments.types'
import { useMemo } from 'react'

interface DepartmentsTableProps {
  onEdit?: (department: Department) => void
}

export function DepartmentsTable({ onEdit }: DepartmentsTableProps) {
  const { departments, loading, meta, query, setQuery, refetch } = useDepartmentsList()
  const { confirmDelete, loading: isDeleting } = useDepartmentActions()

  const handlePageChange = (page: number) => {
    if (!meta) return
    const safe = Math.min(Math.max(page, 1), meta.totalPages)
    setQuery((prev) => ({ ...prev, page: safe }))
  }

  const handleLimitChange = (value: string) => {
    const limit = Number(value)
    setQuery((prev) => ({ ...prev, limit, page: 1 }))
  }

  if (loading) {
    return <DepartmentsTableSkeleton />
  }

  if (!departments?.length) {
    return (
      <div className="rounded-md border p-6 text-center text-sm text-muted-foreground">
        No departments found.
      </div>
    )
  }

  return (
    <div className="space-y-4">
      <div className="overflow-hidden rounded-sm border bg-white">
        <Table>
          <TableHeader>
            <TableRow className="bg-slate-50/60">
              <TableHead className='font-semibold'>Title</TableHead>
              <TableHead className='font-semibold'>Jobs</TableHead>
              <TableHead className="text-right font-semibold">Actions</TableHead>
            </TableRow>
          </TableHeader>

          <TableBody>
            {departments.map((department, idx) => (
              <TableRow
                key={department._id}
                className={cn(idx % 2 === 0 ? 'bg-white' : 'bg-slate-50/40')}
              >
                <TableCell className="font-medium text-slate-900">
                  {department.title}
                </TableCell>

                <TableCell>
                  <Badge variant="secondary" className="font-mono text-white text-xs">
                    {department.jobsCount ?? 0} posted jobs
                  </Badge>
                </TableCell>

                <TableCell className="text-right">
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild>
                      <Button
                        variant="ghost"
                        size="icon"
                        className="h-8 w-8"
                      >
                        <MoreHorizontal className="h-4 w-4" />
                      </Button>
                    </DropdownMenuTrigger>

                    <DropdownMenuContent align="end">
                      <DropdownMenuItem onClick={() => onEdit?.(department)}>
                        <Pencil className="mr-2 h-4 w-4" />
                        Edit
                      </DropdownMenuItem>

                      <DropdownMenuItem
                        variant='destructive'
                        disabled={isDeleting}
                        onClick={() => confirmDelete(department)}
                      >
                        <Trash className="mr-2 h-4 w-4" />
                        Delete
                      </DropdownMenuItem>
                    </DropdownMenuContent>
                  </DropdownMenu>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </div>

      <div className="flex flex-wrap items-center justify-between gap-3">
        <div className="text-sm text-muted-foreground">
          Total: {meta?.totalDocs ?? departments.length}
        </div>
        <div className="flex items-center text-sm gap-2">
          Rows per page:{' '}
          <Select value={String(query.limit ?? 10)} onValueChange={handleLimitChange}>
            <SelectTrigger>
              <SelectValue placeholder="Rows" />
            </SelectTrigger>
            <SelectContent>
              {[5, 10, 20, 50].map((opt) => (
                <SelectItem key={opt} value={String(opt)}>
                  {opt}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>

          <Pagination className="w-auto">
            <PaginationContent>
              <PaginationPrevious
                href="#"
                onClick={(e) => {
                  e.preventDefault()
                  handlePageChange((meta?.page ?? 1) - 1)
                }}
                aria-disabled={!meta?.hasPrevPage}
                className={cn(!meta?.hasPrevPage && 'pointer-events-none opacity-50')}
              />

              <PaginationItem>
                <span className="px-2 text-sm text-muted-foreground">
                  Page {meta?.page ?? 1} of {meta?.totalPages ?? 1}
                </span>
              </PaginationItem>

              <PaginationNext
                href="#"
                onClick={(e) => {
                  e.preventDefault()
                  handlePageChange((meta?.page ?? 1) + 1)
                }}
                aria-disabled={!meta?.hasNextPage}
                className={cn(!meta?.hasNextPage && 'pointer-events-none opacity-50')}
              />
            </PaginationContent>
          </Pagination>
        </div>
      </div>
    </div>
  )
}

function DepartmentsTableSkeleton() {
  return (
    <div className="rounded-md border">
      <Table>
        <TableHeader>
          <TableRow>
            <TableHead>Name</TableHead>
            <TableHead>Members</TableHead>
            <TableHead>Status</TableHead>
            <TableHead />
          </TableRow>
        </TableHeader>

        <TableBody>
          {Array.from({ length: 5 }).map((_, i) => (
            <TableRow key={i}>
              <TableCell>
                <Skeleton className="h-4 w-40" />
              </TableCell>
              <TableCell>
                <Skeleton className="h-4 w-10" />
              </TableCell>
              <TableCell>
                <Skeleton className="h-5 w-16" />
              </TableCell>
              <TableCell>
                <Skeleton className="h-8 w-8" />
              </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </div>
  )
}
